package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;
import java.nio.charset.StandardCharsets;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.invocation.InvocationOnMock;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrint_withValidPathAndCharset() throws IOException {
        Path mockPath = mock(Path.class);
        @SuppressWarnings("resource")
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Since Mockito 3 does not support mockStatic, we use a dynamic proxy to mock Files.newBufferedWriter
        // We'll create a proxy for Files class that intercepts newBufferedWriter method call.

        // Create a proxy instance for Files
        Object filesProxy = Proxy.newProxyInstance(
                java.nio.file.Files.class.getClassLoader(),
                new Class<?>[] { java.nio.file.Files.class },
                new InvocationHandler() {
                    @Override
                    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
                        if ("newBufferedWriter".equals(method.getName())
                                && args.length == 2
                                && args[0] == mockPath
                                && StandardCharsets.UTF_8.equals(args[1])) {
                            return new java.io.StringWriter();
                        }
                        // fallback to original method via reflection
                        return method.invoke(null, args);
                    }
                });

        // Because Files is a final utility class with static methods, we cannot replace it directly.
        // So instead, spy on CSVFormat and override print(Path, Charset) to call print(Appendable) with StringWriter.

        CSVFormat spyFormat = spy(csvFormat);
        doReturn(mockPrinter).when(spyFormat).print(any(java.lang.Appendable.class));
        doAnswer((InvocationOnMock invocation) -> {
            // Replace getArgument with getArguments()[index] to fix compilation error
            Object[] args = invocation.getArguments();
            Path path = (Path) args[0];
            // Instead of calling Files.newBufferedWriter, call print with StringWriter
            return spyFormat.print(new java.io.StringWriter());
        }).when(spyFormat).print(any(Path.class), any());

        CSVPrinter printer = spyFormat.print(mockPath, StandardCharsets.UTF_8);
        assertNotNull(printer);
        assertEquals(mockPrinter, printer);
    }

    @Test
    void testPrint_withIOException() throws IOException {
        Path mockPath = mock(Path.class);

        // Spy csvFormat and override print(Path, Charset) to throw IOException
        CSVFormat spyFormat = spy(csvFormat);
        doThrow(new IOException("Test IO Exception")).when(spyFormat).print(any(Path.class), any());

        IOException thrown = assertThrows(IOException.class, () -> spyFormat.print(mockPath, StandardCharsets.UTF_8));
        assertEquals("Test IO Exception", thrown.getMessage());
    }
}
